            true // documentSecurity: allow documents to have their own permissions
        );

        // 3. Create Attributes
        // Note: Attribute creation is async. In production, poll for status before creating documents.
        await databases.createStringAttribute(
            database.$id, 
            collection.$id, 
            'title', 
            255, // max length
            true // required
        );

        await databases.createBooleanAttribute(
            database.$id, 
            collection.$id, 
            'completed', 
            true // required
        );

        await databases.createDatetimeAttribute(
            database.$id, 
            collection.$id, 
            'dueDate', 
            false // optional
        );

        // Small delay to allow attributes to process (or implement proper polling in production)
        await new Promise(resolve => setTimeout(resolve, 2000));

        // 4. Insert Document
        const document = await databases.createDocument(
            database.$id,
            collection.$id,
            ID.unique(),
            {
                title: 'Complete Appwrite integration',
                completed: false,
                dueDate: new Date('2024-12-31T23:59:59.000Z').toISOString()
            }
        );

