    fileSecurity: true, // Enable file-level permissions
    enabled: true,
    maximumFileSize: 5 * 1024 * 1024, // 5MB
    allowedFileExtensions: ['jpg', 'jpeg', 'png', 'gif', 'webp'],
    permissions: [
        Permission.read(Role.any()),           // Anyone can read files
        Permission.create(Role.user()),        // Authenticated users can upload
        Permission.update(Role.user('[USER_ID]')), // Specific user can update
        Permission.delete(Role.user('[USER_ID]')), // Specific user can delete
    ]
});

console.log('Bucket created:', bucket.$id);

// ============================================
// 2. UPLOAD A FILE (Client-side)
// ============================================
// For web apps - upload from file input

async function uploadImage(fileInputId: string, bucketId: string) {
    const fileElement = document.getElementById(fileInputId) as HTMLInputElement;
    const file = fileElement.files?.[0];

    if (!file) {
        throw new Error('No file selected');
    }

    const uploadedFile = await storage.createFile({
        bucketId: bucketId,
        fileId: ID.unique(),
        file: file,
        permissions: [
            Permission.read(Role.any()),              // Public read access
            Permission.update(Role.user('[USER_ID]')), // Owner can update
            Permission.delete(Role.user('[USER_ID]')), // Owner can delete
        ]
    });

    console.log('File uploaded:', uploadedFile.$id);
    return uploadedFile;
}

