    const uploadedFile = await serverStorage.createFile({
        bucketId: bucketId,
        fileId: ID.unique(),
        file: InputFile.fromPath(filePath, 'image.png'),
        permissions: [
            Permission.read(Role.any()),
            Permission.update(Role.user('[USER_ID]')),
            Permission.delete(Role.user('[USER_ID]')),
        ]
    });

    return uploadedFile;
}

