function getImagePreviewUrl(bucketId: string, fileId: string): string {
    const previewUrl = storage.getFilePreview({
        bucketId: bucketId,
        fileId: fileId,
        width: 300,      // Optional: resize width
        height: 300,     // Optional: resize height
        gravity: 'center', // Optional: crop gravity
        quality: 90,     // Optional: JPEG quality (1-100)
        // format: 'webp', // Optional: output format
    });

    return previewUrl;
}

// ============================================
// 5. COMPLETE EXAMPLE
// ============================================
