export default async ({ req, res, log, error }) => {
    // Log the incoming request
    log('Processing greeting request');

    // Check if the request has a JSON body with a name field
    if (!req.bodyJson || !req.bodyJson.name) {
        error('Missing name field in request body');
        return res.json({ error: 'Name is required' }, 400);
    }

